from typing import List


def rolling_max(numbers: List[int]) -> List[int]:
    max_list = []
    if not numbers:
        return max_list
    current_max = numbers[0]
    max_list.append(current_max)
    for num in numbers[1:]:
        if num > current_max:
            current_max = num
        max_list.append(current_max)
    return max_list

