def sort_array(array):
    if len(array) <= 1:
        return array[:]
    first, last = array[0], array[-1]
    is_odd_sum = (first + last) % 2 == 1
    sorted_copy = array[:]
    if is_odd_sum:
        return sorted(sorted_copy)
    else:
        return sorted(sorted_copy, reverse=True)

