from typing import List

def minPath(grid: List[List[int]], k: int) -> List[int]:
    N = len(grid)
    directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]

    def dfs(x, y, path):
        nonlocal result
        if len(path) == k:
            if not result or path < result:
                result = list(path)
            return

        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            if 0 <= nx < N and 0 <= ny < N:
                dfs(nx, ny, path + [grid[nx][ny]])

    result = []
    start_values = set(range(1, min(k + 1, N * N) + 1))

    for i in range(N):
        for j in range(N):
            if grid[i][j] in start_values:
                dfs(i, j, [grid[i][j]])

    return result

